import { useState } from "react";
import base from "./pizza_base.png";

const toppings = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️"];

const toppingPrices = {
  "🍄": 40,
  "🧀": 45,
  "🌽": 30,
  "🍍": 35,
  "🧅": 20,
  "🌶️": 25,
};

const BASE_PRICE = 299;

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  function handleSelectTopping(topping) {
    setSelected(topping);
  }

  function handlePizzaClick(event) {
    const topping = {
      topping: selected,
      x: event.nativeEvent.offsetX,
      y: event.nativeEvent.offsetY,
    };

    setPizza(pizza => [...pizza, topping]);
  }

  function calculateTotal() {
    let total = BASE_PRICE;

    for (const topping of pizza) {
      total += toppingPrices[topping.topping];
    }

    return total;
  }

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{calculateTotal()}</h2>

      <p>
        {toppings.map((topping) => (
          <button
            key={topping}
            onClick={() => handleSelectTopping(topping)}
            disabled={selected === topping}
          >
            {topping}
          </button>
        ))}
      </p>

      <figure
        onClick={handlePizzaClick}
        style={{
          position: "relative",
        }}
      >
        <img src={base} alt="Pizza" height={500} />

        {pizza.map((topping, index) => (
          <p
            key={index}
            style={{
              position: "absolute",
              left: topping.x,
              top: topping.y,
			  pointerEvents: "none",
			  transform: "translate(50%, -50%)",
            }}
          >
            {topping.topping}
          </p>
        ))}
      </figure>
    </main>
  );
}
